Here is some sample code for a Discord bot with a /ban slash command using discord.js v14:

```js
const { Client, GatewayIntentBits, SlashCommandBuilder } = require('discord.js');

const client = new Client({ intents: [GatewayIntentBits.Guilds] });

client.on('ready', () => {
  console.log(`Logged in as ${client.user.tag}!`);
});

client.on('interactionCreate', async interaction => {
  if (!interaction.isChatInputCommand()) return;

  if (interaction.commandName === 'ban') {
    const user = interaction.options.getUser('user');
    const reason = interaction.options.getString('reason') || 'No reason provided';

    if (!user) {
      await interaction.reply({ content: 'You need to specify a user to ban!', ephemeral: true });
      return;
    }

    try {
      await interaction.guild.members.ban(user, { reason });
      await interaction.reply(`Banned ${user.tag} for "${reason}"`);
    } catch (error) {
      console.error(error);
      await interaction.reply({ content: 'There was an error trying to ban the user!', ephemeral: true });
    }
  }
});

client.on('interactionCreate', async interaction => {
  if (!interaction.isApplicationCommand()) return;

  const banCommand = new SlashCommandBuilder()
    .setName('ban')
    .setDescription('Bans a user')
    .addUserOption(option => 
      option.setName('user')
        .setDescription('The user to ban')
        .setRequired(true))
    .addStringOption(option =>
      option.setName('reason')
        .setDescription('The reason for the ban'));

  await client.application.commands.create(banCommand);
});

client.login('token');
```

The key points are:

- Use SlashCommandBuilder to define the /ban command and options.

- Handle the interaction in the interactionCreate event. 

- Get the target user from interaction.options.

- Ban the user with GuildMemberManager.ban().

- Reply to the interaction to confirm the ban.

- Register the command using client.application.commands.create().

This allows the bot to handle /ban slash command interactions and ban the specified user. Additional checks and error handling can be added as needed.

