Here is an example of how to write a basic first person controller script in GDScript for Godot 3.x using a KinematicBody node:

```python
extends KinematicBody

export var speed = 10
export var sensitivity = 0.1
export var gravity = 20

var vel = Vector3()
var mouse_axis = Vector2()

func _ready():
  Input.set_mouse_mode(Input.MOUSE_MODE_CAPTURED)

func _input(event):
  if event is InputEventMouseMotion:
    mouse_axis = event.relative * sensitivity

func _physics_process(delta):
  var dir = Vector3()
  dir.x = Input.get_action_strength("move_right") - Input.get_action_strength("move_left")
  dir.z = Input.get_action_strength("move_back") - Input.get_action_strength("move_forward")
  dir = dir.normalized()

  vel.x = dir.x * speed
  vel.z = dir.z * speed
  vel.y -= gravity * delta

  var _vel = move_and_slide(vel, Vector3.UP)

  rotate_y(-mouse_axis.x * delta)
```

In Godot 4.x, the equivalent to KinematicBody is CharacterBody. The script would need to be updated like this:

```python
extends CharacterBody

export var speed = 10 
export var sensitivity = 0.1
export var gravity = 20

var vel = Vector3()
var mouse_axis = Vector2() 

func _ready():
  Input.set_mouse_mode(Input.MOUSE_MODE_CAPTURED)

func _input(event):
  if event is InputEventMouseMotion:
    mouse_axis = event.relative * sensitivity

func _physics_process(delta):
  var dir = Vector3()
  dir.x = Input.get_action_strength("move_right") - Input.get_action_strength("move_left") 
  dir.z = Input.get_action_strength("move_back") - Input.get_action_strength("move_forward")
  dir = dir.normalized()

  vel.x = dir.x * speed
  vel.z = dir.z * speed
  vel.y -= gravity * delta

  velocity = vel

  rotate_body_y(-mouse_axis.x * delta)
```

The main changes are using CharacterBody instead of KinematicBody, setting the velocity property instead of using move_and_slide, and using rotate_body_y instead of just rotate_y.
